SELECT AVG(ces_value) AS avg_ces_value
FROM pollution_data
WHERE station_id = 0 AND measurement_date BETWEEN '1992-01-01' AND '1992-01-31';

SELECT measurement_date, ces_value
FROM pollution_data
WHERE ces_value > 0.5;

SELECT AVG(ces_value) AS overall_average_ces
FROM pollution_data
WHERE ces_value IS NOT NULL;

SELECT measurement_date, MAX(ces_value) AS max_ces_value, MAX(mer_value) AS max_mer_value
FROM pollution_data
WHERE measurement_date = '2023-05-01';

SELECT measurement_date, xal_value
FROM pollution_data
WHERE xal_value = (SELECT MAX(xal_value) FROM pollution_data);
